"""
OrangeTree Global — Invoice / Receipt Extractor (UC7)
Powered by Claude API (Anthropic)
Run: streamlit run uc7_invoice_extractor.py
"""

import streamlit as st
import anthropic
import json
import base64
import csv
import io
from datetime import datetime

LOGO_B64 = ""
LOGO_HTML = '<img src="data:image/svg+xml;base64,' + LOGO_B64 + '" style="width:100%;max-width:220px;display:block;margin-bottom:4px;">'

st.set_page_config(
    page_title="Invoice Extractor | OrangeTree Global",
    page_icon="🌳",
    layout="wide",
)

st.markdown("""
<style>
    .section-header {
        border-left: 4px solid #F36621;
        padding: 0.3rem 0.8rem;
        background: #fff3ee;
        border-radius: 0 4px 4px 0;
        margin: 1.2rem 0 0.6rem 0;
        font-weight: 600;
    }
    .field-row {
        background: #f8f9fa;
        border-radius: 6px;
        padding: 0.5rem 0.8rem;
        margin: 0.25rem 0;
        font-size: 0.9rem;
    }
    .field-label {
        color: #888;
        font-size: 0.78rem;
        text-transform: uppercase;
        letter-spacing: 0.04em;
    }
    .register-table th {
        background: #F36621;
        color: white;
        padding: 6px 10px;
    }
    .total-box {
        background: #fff3ee;
        border-left: 4px solid #F36621;
        padding: 0.75rem 1rem;
        border-radius: 4px;
        font-size: 1.1rem;
        font-weight: 600;
    }
</style>
""", unsafe_allow_html=True)

st.markdown(
    f'<img src="data:image/svg+xml;base64,{LOGO_B64}" style="width:280px;max-width:100%;display:block;margin-bottom:12px;">',
    unsafe_allow_html=True
)
st.markdown("## Invoice & Receipt Extractor")
st.markdown("Upload invoice images or PDFs — Claude extracts vendor, date, amount, GST and category automatically into a running register.")
st.divider()

with st.sidebar:
    st.markdown(LOGO_HTML, unsafe_allow_html=True)
    st.markdown("---")
    api_key = st.text_input("Anthropic API Key", type="password", help="Get from console.anthropic.com")
    model = st.selectbox("Model", ["claude-opus-4-8", "claude-sonnet-4-6"], index=1,
        help="Sonnet or Opus recommended for accurate invoice reading")
    st.markdown("---")
    st.markdown("**Settings**")
    currency = st.selectbox("Currency", ["INR (₹)", "USD ($)", "GBP (£)", "EUR (€)"])
    default_category = st.selectbox("Default expense category", [
        "Auto-detect", "Raw Materials", "Operations", "Marketing", "Travel",
        "Office Supplies", "Utilities", "Professional Services", "Other"
    ])
    st.markdown("---")
    if st.button("Clear register", use_container_width=True):
        st.session_state["register"] = []
        st.rerun()
    st.markdown("---")
    st.info("UC7 of OrangeTree's AI SME Suite. Powered by Claude API.", icon="ℹ️")

if "register" not in st.session_state:
    st.session_state["register"] = []

col_upload, col_result = st.columns([1, 1], gap="large")

with col_upload:
    st.markdown('<div class="section-header">Upload Invoice or Receipt</div>', unsafe_allow_html=True)
    st.markdown("Supports photos (JPG, PNG) and PDF invoices.")

    uploaded = st.file_uploader("Upload invoice",
        type=["jpg", "jpeg", "png", "pdf"],
        label_visibility="collapsed")

    if uploaded:
        if uploaded.type in ["image/jpeg", "image/jpg", "image/png"]:
            st.image(uploaded, caption=uploaded.name, use_container_width=True)
        else:
            st.info(f"PDF uploaded: {uploaded.name}")

    extract_btn = st.button("Extract Invoice Data", type="primary",
        use_container_width=True, disabled=(not uploaded))

    if not uploaded:
        st.caption("Upload an invoice or receipt image/PDF above.")

with col_result:
    st.markdown('<div class="section-header">Extracted Data</div>', unsafe_allow_html=True)

    if extract_btn and uploaded:
        if not api_key:
            st.error("Enter your Anthropic API key in the sidebar.")
            st.stop()

        with st.spinner("Reading invoice..."):
            try:
                client = anthropic.Anthropic(api_key=api_key)

                system = """You are an invoice extraction expert. Extract all available fields from the invoice and return a JSON object with these exact keys:
{
  "vendor_name": "Name of seller/supplier",
  "invoice_number": "Invoice or receipt number",
  "invoice_date": "Date of invoice (DD/MM/YYYY format)",
  "due_date": "Payment due date if present",
  "line_items": [{"description": "...", "quantity": "...", "unit_price": "...", "amount": "..."}],
  "subtotal": "Amount before tax",
  "gst_percentage": "GST rate if shown",
  "gst_amount": "GST amount",
  "total_amount": "Final total including tax",
  "payment_method": "Cash/UPI/Card/etc if shown",
  "gstin": "Vendor GSTIN if shown",
  "category": "Expense category (Raw Materials/Operations/Marketing/Travel/Office Supplies/Utilities/Professional Services/Other)",
  "notes": "Any other relevant detail"
}
Return ONLY valid JSON. Use null for fields not found in the invoice."""

                if uploaded.type in ["image/jpeg", "image/jpg", "image/png"]:
                    img_data = base64.standard_b64encode(uploaded.read()).decode("utf-8")
                    media_type = "image/jpeg" if uploaded.type in ["image/jpeg", "image/jpg"] else "image/png"
                    response = client.messages.create(
                        model=model,
                        max_tokens=1500,
                        system=system,
                        messages=[{
                            "role": "user",
                            "content": [
                                {"type": "image", "source": {"type": "base64", "media_type": media_type, "data": img_data}},
                                {"type": "text", "text": f"Extract all invoice data. Category preference: {default_category}."}
                            ]
                        }]
                    )
                else:
                    try:
                        import pdfplumber
                        uploaded.seek(0)
                        with pdfplumber.open(uploaded) as pdf:
                            pdf_text = "\n".join(page.extract_text() or "" for page in pdf.pages)
                    except Exception:
                        pdf_text = "[PDF text extraction failed — install pdfplumber: pip3 install pdfplumber]"

                    response = client.messages.create(
                        model=model,
                        max_tokens=1500,
                        system=system,
                        messages=[{"role": "user", "content": f"Extract invoice data from this text:\n\n{pdf_text[:4000]}"}]
                    )

                raw = response.content[0].text.strip()
                if "```" in raw:
                    raw = raw.split("```")[1]
                    if raw.startswith("json"):
                        raw = raw[4:]
                data = json.loads(raw)

                st.success("Invoice extracted successfully")

                fields = [
                    ("Vendor", data.get("vendor_name")),
                    ("Invoice No.", data.get("invoice_number")),
                    ("Date", data.get("invoice_date")),
                    ("Due Date", data.get("due_date")),
                    ("Subtotal", data.get("subtotal")),
                    ("GST %", data.get("gst_percentage")),
                    ("GST Amount", data.get("gst_amount")),
                    ("Category", data.get("category")),
                    ("Payment Method", data.get("payment_method")),
                    ("GSTIN", data.get("gstin")),
                ]
                for label, value in fields:
                    if value:
                        st.markdown(f'<div class="field-row"><span class="field-label">{label}</span><br>{value}</div>', unsafe_allow_html=True)

                total = data.get("total_amount", "N/A")
                st.markdown(f'<div class="total-box">Total: {currency.split()[0]} {total}</div>', unsafe_allow_html=True)

                if data.get("line_items"):
                    with st.expander("Line items"):
                        for item in data["line_items"]:
                            st.write(f"• {item.get('description','—')} — Qty: {item.get('quantity','—')} × {item.get('unit_price','—')} = {item.get('amount','—')}")

                register_entry = {
                    "File": uploaded.name,
                    "Vendor": data.get("vendor_name", ""),
                    "Date": data.get("invoice_date", ""),
                    "Invoice No.": data.get("invoice_number", ""),
                    "Total": data.get("total_amount", ""),
                    "GST Amount": data.get("gst_amount", ""),
                    "Category": data.get("category", ""),
                    "Payment": data.get("payment_method", ""),
                    "GSTIN": data.get("gstin", ""),
                }
                st.session_state["register"].append(register_entry)

            except json.JSONDecodeError:
                st.error("Could not parse extraction. Try again or use a clearer image.")
                st.code(raw, language="text")
            except Exception as e:
                st.error(f"Error: {e}")

if st.session_state["register"]:
    st.divider()
    st.markdown("## Running Register")
    st.markdown(f"{len(st.session_state['register'])} invoice(s) this session")

    import pandas as pd
    df = pd.DataFrame(st.session_state["register"])
    st.dataframe(df, use_container_width=True)

    csv_buf = io.StringIO()
    df.to_csv(csv_buf, index=False)
    st.download_button(
        "Download Register as CSV",
        data=csv_buf.getvalue(),
        file_name=f"invoice_register_{datetime.now().strftime('%Y%m%d_%H%M')}.csv",
        mime="text/csv",
        use_container_width=True
    )

st.caption("OrangeTree Global | AI SME Suite — UC7: Invoice & Receipt Extractor")
